    const MAX_VAL = 5000;

    // Helper function to calculate digit sum
    const getDigitSum = (n) => {
        let sum = 0;
        if (n < 0) return -1;
        while (n > 0) {
            sum += n % 10;
            n = Math.floor(n / 10);
        }
        return sum;
    };

