    const candidates = new Array(51).fill(0).map(() => []);
    for (let x = 0; x <= MAX_VAL; x++) {
        const s = getDigitSum(x);
        if (s <= 50) {
            candidates[s].push(x);
        }
    }

    const N = digitSum.length;

    // DP_Prev[x]: Number of ways to form a valid prefix ending exactly at value x in the previous step (i-1)
    // Size MAX_VAL + 1 = 5001
    let dpPrev = new Array(MAX_VAL + 1).fill(0);

    // Step 2: Base Case (i = 0)
    const S0 = digitSum[0];
    if (S0 <= 50) {
        for (const x of candidates[S0]) {
            dpPrev[x] = 1;
        }
    } else {
        // If the first required digit sum is impossible, result is 0
        return 0;
    }

