    const MOD = 1000000007;
    const MAX_VAL = 5000;

    // Helper function to calculate digit sum
    const getDigitSum = (n) => {
        let sum = 0;
        if (n < 0) return -1;
        while (n > 0) {
            sum += n % 10;
            n = Math.floor(n / 10);
        }
        return sum;
    };

    // Step 1: Precalculate Candidates[S] = list of numbers x in [0, 5000] where DS(x) = S
    const candidates = new Array(51).fill(0).map(() => []);
    for (let x = 0; x <= MAX_VAL; x++) {
        const s = getDigitSum(x);
        if (s <= 50) {
            candidates[s].push(x);
        }
